    /// <summary>
    /// 添加系统角色
    /// </summary>
    /// <param name="regionType">配置中的维度编号</param>
    /// <param name="roles"></param>
    /// <returns></returns>
    [HttpPost("{regionType}")]
    public TPResponse<int> AddSysRole([FromRoute] int regionType, [FromBody] List<Req_NewRole> roles)
    {
        var (account, username) = ScopeUser.GetUserAccountName();
        var tenant = ScopeUser.GetUserTenant();

        var (region, regionTitle) = AuthCommon.GetRegion(regionType);

        if (string.IsNullOrEmpty(region))
        {
            return TPResponse.Bad<int>("错误的角色维度");
        }

        var roleToAdd = new List<Auth_role_Class>();

        foreach (var role in roles)
        {
            if (role.Id == Guid.Empty)
            {
                role.Id = Guid.NewGuid();
                role.Parent_id = Guid.Empty;
            }
            var tableRow = role.Cast(tenant, account, username, region, regionTitle);
            roleToAdd.Add(tableRow);
        }
        var res = AuthBusiness.Add(roleToAdd);
        return TPResponse.New(res);
    }

