    /// <summary>
    /// 给一群人添加一个角色
    /// </summary>
    /// <param name="userAccounts"></param>
    /// <param name="roleType"></param>
    /// <param name="roleCode"></param>
    /// <param name="UserBusiness"></param>
    /// <returns></returns>
    [HttpPost("{roleType}/{roleCode}")]
    public TPResponse<int> AddRoleForUsers([FromRoute] int roleType,
        [FromRoute] string roleCode, [FromBody] List<string> userAccounts,
        [FromServices] IUser_Business UserBusiness)
    {
        var (optAccount, optUserName) = ScopeUser.GetUserAccountName();
        var optTenant = ScopeUser.GetUserTenant();
        var (region, regionTitle) = AuthCommon.GetRegion(roleType);

        //这里保证userAccounts只能是账号信息
        var users = UserBusiness.SearchBy_Accounts(userAccounts);

        var assets = new List<Auth_assets_Class>();
        foreach (var user in users)
        {
            if (user.Tenant != optTenant)
            {
                continue;
            }

            var asset = Auth_assets_Class.CastForUser(
                optAccount, optUserName, optTenant,
                region, user.Tenant, roleCode);

            assets.Add(asset);
        }
        return TPResponse.New(AuthBusiness.Add(assets));
    }

    /// <summary>
    /// 添加角色继承关系的一组角色资源
    /// TODO 避免直接给人员添加
    /// </summary>
    /// <param name="roleType">角色维度</param>
    /// <param name="roleGroup">继承关系的角色组</param>
    /// <param name="UserBusiness"></param>
    /// <returns></returns>
    [HttpPost("{roleType}")]
    public TPResponse<int> AddRoles([FromRoute] int roleType,
        [FromBody] List<Req_RoleHaving> roleGroup,
        [FromServices] IUser_Business UserBusiness)
    {
        var (account, userName) = ScopeUser.GetUserAccountName();
        var tenant = ScopeUser.GetUserTenant();
        var (region, regionTitle) = AuthCommon.GetRegion(roleType);

        var userAccounts = UserBusiness
            .SearchBy_Tenant(tenant)
            .Select(x => x.Account)
            .ToList();

        var assetsToAdd = new List<Auth_assets_Class>();
        foreach (var group in roleGroup)
        {
            if (userAccounts.Contains(group.RoleCode))
            {
                return TPResponse.Bad<int>("不允许为个人" + group.RoleCode + "添加角色组");
            }

            if (userAccounts.Contains(group.HavingRole))
            {
                return TPResponse.Bad<int>("不允许个人账号" + group.HavingRole + "成为角色");
            }

            var asset = group.Cast(account, userName, tenant, region);
            if (asset != null)
            {
                assetsToAdd.Add(asset);
            }
        }
        return TPResponse.New(AuthBusiness.Add(assetsToAdd));

    }

