    /// <summary>
    /// 处理资源
    /// </summary>
    /// <param name="roleCode">角色编码</param>
    /// <param name="assetType">资源类型，与appsettings匹配</param>
    /// <param name="patternList">资源特征码</param>
    /// <returns></returns>
    private (bool Status, string Msg, int Result) ExecuteAssets(
        string roleCode, int assetType, List<List<string>> patternList)
    {
        var (optAccount, optUserName) = ScopeUser.GetUserAccountName();
        var tenant = ScopeUser.GetUserTenant();

        var role = AuthBusiness.SearchBy_RoleCode_Tenant(roleCode, tenant);

        if (role.Count < 1)
        {
            return (false, "该角色编码不存在", -1);
        }

        var (type, asset) = AuthCommon.GetAssetsType(assetType); //此处需要跟appsettings中的资源数组匹配

        var assetsToAdd = new List<Auth_assets_Class>();

        foreach (var patterns in patternList)
        {
            var newAsset = Auth_assets_Class.CastFromAsset(
                optAccount, optUserName, tenant, type,
                roleCode, asset, patterns);
            assetsToAdd.Add(newAsset);
        }

        var res = AuthBusiness.Add(assetsToAdd);
        return (true, "OK", res);

    }

